def binary_search(arr, target):
    """Return index of target in sorted array, or -1 if not found."""
    left = 0
    right = len(arr)  # Bug here or nearby

    while left < right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            left = mid
        else:
            right = mid - 1

    return -1
